1	//! Clause parser: turns a token stream into `Clause` structures.
2	//!
3	//! Grammar (subset for ancestor.pl, color.pl, liar puzzle):
4	//!   clause := term ('.' | ':-' body '.') | '?-' body '.'
5	//!   body   := goal (',' goal)*
6	//!   goal   := term | '\+' goal | '!'
7	//!   term   := atom | var | int | atom '(' term (',' term)* ')' | list
8	//!   list   := '[]' | '[' term (',' term)* ( '|' term )? ']'
9	//!
10	//! Lists desugar to Struct('.'/2, [H, T]); Nil is the empty list.
11	//!
12	//! Port shape: subterms of a clause live in a flat arena
13	//! (`BoundedArr<Term, MAX_SUBTERMS>`) addressed by `TermIdx` so that
14	//! SNOBOL4 can mirror the layout with a single ARRAY per clause.
15	
16	use crate::port::{BoundedArr, BoundedStr};
17	use crate::tokenize::{Token, MAX_TOKENS};
18	use core::mem::discriminant;
19	use thiserror::Error;
20	
21	pub type AtomId = u16;
22	pub type VarSlot = u8;
23	pub type TermIdx = u8;
24	
25	pub const MAX_ATOMS: usize = 50;
26	pub const MAX_CLAUSE_VARS: usize = 16;
27	pub const MAX_SUBTERMS: usize = 64;
28	pub const MAX_BODY: usize = 16;
29	pub const MAX_CLAUSES: usize = 64;
30	pub const MAX_ARGS: usize = 8;
31	pub const NAME_CAP: usize = 32;
32	
33	#[derive(Clone, Copy, Debug, PartialEq, Eq)]
34	pub enum Term {
35	    Atom(AtomId),
36	    Var(VarSlot),
37	    Int(i32),
38	    Struct { functor: AtomId, args: BoundedArr<TermIdx, MAX_ARGS> },
39	    Nil,
40	}
41	
42	#[derive(Clone, Copy, Debug, PartialEq, Eq)]
43	pub enum ClauseKind {
44	    Fact,
45	    Rule,
46	    Query,
47	}
48	
49	#[derive(Clone, Copy, Debug)]
50	pub struct AtomTable {
51	    names: BoundedArr<BoundedStr<NAME_CAP>, MAX_ATOMS>,
52	}
53	
54	impl AtomTable {
55	    pub const fn new() -> Self {
56	        Self { names: BoundedArr::new() }
57	    }
58	
59	    pub fn intern(&mut self, s: &str) -> Result<AtomId, ParseError> {
60	        let key = BoundedStr::<NAME_CAP>::from_str(s).map_err(|_| ParseError::AtomOverflow)?;
61	        for i in 0..self.names.len() {
62	            if self.names.get(i).map(|n| *n == key).unwrap_or(false) {
63	                return Ok(i as AtomId);
64	            }
65	        }
66	        let id = self.names.len() as AtomId;
67	        self.names.push(key).map_err(|_| ParseError::AtomOverflow)?;
68	        Ok(id)
69	    }
70	
71	    pub fn name(&self, id: AtomId) -> Option<&BoundedStr<NAME_CAP>> {
72	        self.names.get(id as usize)
73	    }
74	
75	    pub fn len(&self) -> usize {
76	        self.names.len()
77	    }
78	
79	    pub fn is_empty(&self) -> bool {
80	        self.names.is_empty()
81	    }
82	}
83	
84	impl Default for AtomTable {
85	    fn default() -> Self {
86	        Self::new()
87	    }
88	}
89	
90	#[derive(Clone, Copy, Debug)]
91	pub struct VarTable {
92	    names: BoundedArr<BoundedStr<NAME_CAP>, MAX_CLAUSE_VARS>,
93	}
94	
95	impl VarTable {
96	    pub const fn new() -> Self {
97	        Self { names: BoundedArr::new() }
98	    }
99	
100	    pub fn slot(&mut self, s: &str) -> Result<VarSlot, ParseError> {
101	        let key = BoundedStr::<NAME_CAP>::from_str(s).map_err(|_| ParseError::VarOverflow)?;
102	        for i in 0..self.names.len() {
103	            if self.names.get(i).map(|n| *n == key).unwrap_or(false) {
104	                return Ok(i as VarSlot);
105	            }
106	        }
107	        let id = self.names.len() as VarSlot;
108	        self.names.push(key).map_err(|_| ParseError::VarOverflow)?;
109	        Ok(id)
110	    }
111	
112	    pub fn name(&self, slot: VarSlot) -> Option<&BoundedStr<NAME_CAP>> {
113	        self.names.get(slot as usize)
114	    }
115	
116	    pub fn len(&self) -> usize {
117	        self.names.len()
118	    }
119	
120	    pub fn is_empty(&self) -> bool {
121	        self.names.is_empty()
122	    }
123	}
124	
125	impl Default for VarTable {
126	    fn default() -> Self {
127	        Self::new()
128	    }
129	}
130	
131	#[derive(Clone, Copy, Debug)]
132	pub struct Clause {
133	    pub kind: ClauseKind,
134	    pub head: Term,
135	    pub body: BoundedArr<Term, MAX_BODY>,
136	    pub subterms: BoundedArr<Term, MAX_SUBTERMS>,
137	    pub vars: VarTable,
138	}
139	
140	impl Clause {
141	    pub const fn new() -> Self {
142	        Self {
143	            kind: ClauseKind::Fact,
144	            head: Term::Nil,
145	            body: BoundedArr::new(),
146	            subterms: BoundedArr::new(),
147	            vars: VarTable::new(),
148	        }
149	    }
150	
151	    pub fn subterm(&self, idx: TermIdx) -> Option<&Term> {
152	        self.subterms.get(idx as usize)
153	    }
154	}
155	
156	impl Default for Clause {
157	    fn default() -> Self {
158	        Self::new()
159	    }
160	}
161	
162	#[derive(Debug, Error, Clone, Copy, PartialEq, Eq)]
163	pub enum ParseError {
164	    #[error("unexpected end of input at token {0}")]
165	    UnexpectedEof(usize),
166	    #[error("unexpected token at position {0}")]
167	    UnexpectedToken(usize),
168	    #[error("missing '.' at position {0}")]
169	    MissingDot(usize),
170	    #[error("mismatched '(' at position {0}")]
171	    MismatchedParen(usize),
172	    #[error("mismatched '[' at position {0}")]
173	    MismatchedBracket(usize),
174	    #[error("bad operator at position {0}")]
175	    BadOperator(usize),
176	    #[error("empty struct argument list at position {0}")]
177	    EmptyArgs(usize),
178	    #[error("atom table overflow")]
179	    AtomOverflow,
180	    #[error("var table overflow")]
181	    VarOverflow,
182	    #[error("subterm arena overflow")]
183	    SubtermOverflow,
184	    #[error("too many args for struct")]
185	    TooManyArgs,
186	    #[error("too many body goals")]
187	    TooManyGoals,
188	    #[error("too many clauses")]
189	    TooManyClauses,
190	}
191	
192	struct Parser<'a> {
193	    toks: &'a BoundedArr<Token, MAX_TOKENS>,
194	    pos: usize,
195	}
196	
197	impl<'a> Parser<'a> {
198	    fn new(toks: &'a BoundedArr<Token, MAX_TOKENS>) -> Self {
199	        Self { toks, pos: 0 }
200	    }
201	
202	    fn peek(&self) -> Option<Token> {
203	        self.toks.get(self.pos).copied()
204	    }
205	
206	    fn bump(&mut self) -> Option<Token> {
207	        let t = self.toks.get(self.pos).copied()?;
208	        self.pos += 1;
209	        Some(t)
210	    }
211	
212	    fn at_end(&self) -> bool {
213	        matches!(self.peek(), None | Some(Token::Eof))
214	    }
215	}
216	
217	pub fn parse(
218	    toks: &BoundedArr<Token, MAX_TOKENS>,
219	    atoms: &mut AtomTable,
220	) -> Result<BoundedArr<Clause, MAX_CLAUSES>, ParseError> {
221	    let mut p = Parser::new(toks);
222	    let mut clauses: BoundedArr<Clause, MAX_CLAUSES> = BoundedArr::new();
223	    while !p.at_end() {
224	        let clause = parse_clause(&mut p, atoms)?;
225	        clauses.push(clause).map_err(|_| ParseError::TooManyClauses)?;
226	    }
227	    Ok(clauses)
228	}
229	
230	fn parse_clause(p: &mut Parser, atoms: &mut AtomTable) -> Result<Clause, ParseError> {
231	    let mut clause = Clause::new();
232	    if matches!(p.peek(), Some(Token::Query)) {
233	        p.bump();
234	        clause.kind = ClauseKind::Query;
235	        clause.head = Term::Nil;
236	        parse_body(p, atoms, &mut clause)?;
237	        expect_kind(p, &Token::Dot, ParseError::MissingDot(p.pos))?;
238	        return Ok(clause);
239	    }
240	    clause.head = parse_term(p, atoms, &mut clause.subterms, &mut clause.vars)?;
241	    match p.peek() {
242	        Some(Token::Dot) => {
243	            p.bump();
244	            clause.kind = ClauseKind::Fact;
245	        }
246	        Some(Token::Neck) => {
247	            p.bump();
248	            clause.kind = ClauseKind::Rule;
249	            parse_body(p, atoms, &mut clause)?;
250	            expect_kind(p, &Token::Dot, ParseError::MissingDot(p.pos))?;
251	        }
252	        Some(_) => return Err(ParseError::MissingDot(p.pos)),
253	        None => return Err(ParseError::UnexpectedEof(p.pos)),
254	    }
255	    Ok(clause)
256	}
257	
258	fn parse_body(p: &mut Parser, atoms: &mut AtomTable, clause: &mut Clause) -> Result<(), ParseError> {
259	    loop {
260	        let goal = parse_goal(p, atoms, &mut clause.subterms, &mut clause.vars)?;
261	        clause.body.push(goal).map_err(|_| ParseError::TooManyGoals)?;
262	        if matches!(p.peek(), Some(Token::Comma)) {
263	            p.bump();
264	            continue;
265	        }
266	        break;
267	    }
268	    Ok(())
269	}
270	
271	fn parse_goal(
272	    p: &mut Parser,
273	    atoms: &mut AtomTable,
274	    subs: &mut BoundedArr<Term, MAX_SUBTERMS>,
275	    vars: &mut VarTable,
276	) -> Result<Term, ParseError> {
277	    match p.peek() {
278	        Some(Token::Cut) => {
279	            p.bump();
280	            let id = atoms.intern("!")?;
281	            Ok(Term::Atom(id))
282	        }
283	        Some(Token::Not) => {
284	            p.bump();
285	            let inner = parse_goal(p, atoms, subs, vars)?;
286	            let id = atoms.intern("\\+")?;
287	            let idx = push_sub(subs, inner)?;
288	            let mut args: BoundedArr<TermIdx, MAX_ARGS> = BoundedArr::new();
289	            args.push(idx).map_err(|_| ParseError::TooManyArgs)?;
290	            Ok(Term::Struct { functor: id, args })
291	        }
292	        Some(_) => parse_term(p, atoms, subs, vars),
293	        None => Err(ParseError::UnexpectedEof(p.pos)),
294	    }
295	}
296	
297	fn parse_term(
298	    p: &mut Parser,
299	    atoms: &mut AtomTable,
300	    subs: &mut BoundedArr<Term, MAX_SUBTERMS>,
301	    vars: &mut VarTable,
302	) -> Result<Term, ParseError> {
303	    let start = p.pos;
304	    let tok = p.bump().ok_or(ParseError::UnexpectedEof(start))?;
305	    match tok {
306	        Token::Atom(name) => parse_atom_or_struct(p, atoms, subs, vars, &name),
307	        Token::Var(name) => {
308	            let slot = vars.slot(name.as_str())?;
309	            Ok(Term::Var(slot))
310	        }
311	        Token::Int(n) => Ok(Term::Int(n)),
312	        Token::LBracket => parse_list(p, atoms, subs, vars),
313	        Token::Cut | Token::Not => Err(ParseError::BadOperator(start)),
314	        _ => Err(ParseError::UnexpectedToken(start)),
315	    }
316	}
317	
318	fn parse_atom_or_struct(
319	    p: &mut Parser,
320	    atoms: &mut AtomTable,
321	    subs: &mut BoundedArr<Term, MAX_SUBTERMS>,
322	    vars: &mut VarTable,
323	    name: &BoundedStr<NAME_CAP>,
324	) -> Result<Term, ParseError> {
325	    if !matches!(p.peek(), Some(Token::LParen)) {
326	        let id = atoms.intern(name.as_str())?;
327	        return Ok(Term::Atom(id));
328	    }
329	    p.bump();
330	    if matches!(p.peek(), Some(Token::RParen)) {
331	        return Err(ParseError::EmptyArgs(p.pos));
332	    }
333	    let id = atoms.intern(name.as_str())?;
334	    let mut args: BoundedArr<TermIdx, MAX_ARGS> = BoundedArr::new();
335	    loop {
336	        let arg = parse_term(p, atoms, subs, vars)?;
337	        let idx = push_sub(subs, arg)?;
338	        args.push(idx).map_err(|_| ParseError::TooManyArgs)?;
339	        match p.peek() {
340	            Some(Token::Comma) => {
341	                p.bump();
342	                continue;
343	            }
344	            Some(Token::RParen) => {
345	                p.bump();
346	                break;
347	            }
348	            Some(_) => return Err(ParseError::MismatchedParen(p.pos)),
349	            None => return Err(ParseError::UnexpectedEof(p.pos)),
350	        }
351	    }
352	    Ok(Term::Struct { functor: id, args })
353	}
354	
355	fn parse_list(
356	    p: &mut Parser,
357	    atoms: &mut AtomTable,
358	    subs: &mut BoundedArr<Term, MAX_SUBTERMS>,
359	    vars: &mut VarTable,
360	) -> Result<Term, ParseError> {
361	    if matches!(p.peek(), Some(Token::RBracket)) {
362	        p.bump();
363	        return Ok(Term::Nil);
364	    }
365	    let mut elements: BoundedArr<Term, MAX_SUBTERMS> = BoundedArr::new();
366	    loop {
367	        let e = parse_term(p, atoms, subs, vars)?;
368	        elements.push(e).map_err(|_| ParseError::SubtermOverflow)?;
369	        if matches!(p.peek(), Some(Token::Comma)) {
370	            p.bump();
371	            continue;
372	        }
373	        break;
374	    }
375	    let tail = if matches!(p.peek(), Some(Token::Pipe)) {
376	        p.bump();
377	        parse_term(p, atoms, subs, vars)?
378	    } else {
379	        Term::Nil
380	    };
381	    expect_kind(p, &Token::RBracket, ParseError::MismatchedBracket(p.pos))?;
382	    let dot_id = atoms.intern(".")?;
383	    let mut current = tail;
384	    for i in (0..elements.len()).rev() {
385	        let h = *elements.get(i).expect("list fold: element index in range");
386	        let h_idx = push_sub(subs, h)?;
387	        let t_idx = push_sub(subs, current)?;
388	        let mut args: BoundedArr<TermIdx, MAX_ARGS> = BoundedArr::new();
389	        args.push(h_idx).map_err(|_| ParseError::TooManyArgs)?;
390	        args.push(t_idx).map_err(|_| ParseError::TooManyArgs)?;
391	        current = Term::Struct { functor: dot_id, args };
392	    }
393	    Ok(current)
394	}
395	
396	fn push_sub(
397	    subs: &mut BoundedArr<Term, MAX_SUBTERMS>,
398	    t: Term,
399	) -> Result<TermIdx, ParseError> {
400	    let idx = subs.len();
401	    if idx >= u8::MAX as usize {
402	        return Err(ParseError::SubtermOverflow);
403	    }
404	    subs.push(t).map_err(|_| ParseError::SubtermOverflow)?;
405	    Ok(idx as TermIdx)
406	}
407	
408	fn expect_kind(p: &mut Parser, expected: &Token, err: ParseError) -> Result<(), ParseError> {
409	    match p.peek() {
410	        Some(t) if discriminant(&t) == discriminant(expected) => {
411	            p.bump();
412	            Ok(())
413	        }
414	        Some(_) => Err(err),
415	        None => Err(ParseError::UnexpectedEof(p.pos)),
416	    }
417	}
418	
419	#[cfg(test)]
420	mod tests {
421	    use super::*;
422	
423	    fn tstream(arr: &[Token]) -> BoundedArr<Token, MAX_TOKENS> {
424	        let mut out: BoundedArr<Token, MAX_TOKENS> = BoundedArr::new();
425	        for t in arr {
426	            out.push(*t).expect("test stream fits");
427	        }
428	        out.push(Token::Eof).expect("eof fits");
429	        out
430	    }
431	
432	    fn a(s: &str) -> Token {
433	        Token::Atom(BoundedStr::<NAME_CAP>::from_str(s).expect("atom name fits"))
434	    }
435	
436	    fn v(s: &str) -> Token {
437	        Token::Var(BoundedStr::<NAME_CAP>::from_str(s).expect("var name fits"))
438	    }
439	
440	    fn name_of(atoms: &AtomTable, id: AtomId) -> &str {
441	        atoms.name(id).expect("atom id in range").as_str()
442	    }
443	
444	    #[test]
445	    fn parse_single_fact() {
446	        // parent(bob, ann).
447	        let toks = tstream(&[
448	            a("parent"), Token::LParen, a("bob"), Token::Comma, a("ann"),
449	            Token::RParen, Token::Dot,
450	        ]);
451	        let mut atoms = AtomTable::new();
452	        let clauses = parse(&toks, &mut atoms).expect("parse ok");
453	        assert_eq!(clauses.len(), 1);
454	        let c = clauses.get(0).unwrap();
455	        assert_eq!(c.kind, ClauseKind::Fact);
456	        let (name, arity) = match c.head {
457	            Term::Struct { functor, args } => (name_of(&atoms, functor), args.len()),
458	            _ => panic!("head is not struct"),
459	        };
460	        assert_eq!(name, "parent");
461	        assert_eq!(arity, 2);
462	        assert!(c.body.is_empty());
463	    }
464	
465	    #[test]
466	    fn parse_rule_with_single_body_goal() {
467	        // ancestor(X, Y) :- parent(X, Y).
468	        let toks = tstream(&[
469	            a("ancestor"), Token::LParen, v("X"), Token::Comma, v("Y"), Token::RParen,
470	            Token::Neck,
471	            a("parent"), Token::LParen, v("X"), Token::Comma, v("Y"), Token::RParen,
472	            Token::Dot,
473	        ]);
474	        let mut atoms = AtomTable::new();
475	        let clauses = parse(&toks, &mut atoms).expect("parse ok");
476	        assert_eq!(clauses.len(), 1);
477	        let c = clauses.get(0).unwrap();
478	        assert_eq!(c.kind, ClauseKind::Rule);
479	        assert_eq!(c.body.len(), 1);
480	        match c.head {
481	            Term::Struct { functor, args } => {
482	                assert_eq!(name_of(&atoms, functor), "ancestor");
483	                assert_eq!(args.len(), 2);
484	            }
485	            _ => panic!("head shape wrong"),
486	        }
487	        match c.body.get(0).copied().unwrap() {
488	            Term::Struct { functor, args } => {
489	                assert_eq!(name_of(&atoms, functor), "parent");
490	                assert_eq!(args.len(), 2);
491	            }
492	            _ => panic!("body[0] shape wrong"),
493	        }
494	        // Var table shared between head+body: X=0, Y=1.
495	        assert_eq!(c.vars.len(), 2);
496	    }
497	
498	    #[test]
499	    fn parse_query_directive() {
500	        // ?- ancestor(bob, liz).
501	        let toks = tstream(&[
502	            Token::Query,
503	            a("ancestor"), Token::LParen, a("bob"), Token::Comma, a("liz"),
504	            Token::RParen, Token::Dot,
505	        ]);
506	        let mut atoms = AtomTable::new();
507	        let clauses = parse(&toks, &mut atoms).expect("parse ok");
508	        assert_eq!(clauses.len(), 1);
509	        let c = clauses.get(0).unwrap();
510	        assert_eq!(c.kind, ClauseKind::Query);
511	        assert!(matches!(c.head, Term::Nil));
512	        assert_eq!(c.body.len(), 1);
513	    }
