515	    #[test]
516	    fn parse_full_ancestor_program() {
517	        // parent(bob, ann).
518	        // parent(ann, liz).
519	        // ancestor(X, Y) :- parent(X, Y).
520	        // ancestor(X, Y) :- parent(X, Z), ancestor(Z, Y).
521	        // ?- ancestor(bob, liz).
522	        let toks = tstream(&[
523	            // parent(bob, ann).
524	            a("parent"), Token::LParen, a("bob"), Token::Comma, a("ann"),
525	            Token::RParen, Token::Dot,
526	            // parent(ann, liz).
527	            a("parent"), Token::LParen, a("ann"), Token::Comma, a("liz"),
528	            Token::RParen, Token::Dot,
529	            // ancestor(X, Y) :- parent(X, Y).
530	            a("ancestor"), Token::LParen, v("X"), Token::Comma, v("Y"), Token::RParen,
531	            Token::Neck,
532	            a("parent"), Token::LParen, v("X"), Token::Comma, v("Y"), Token::RParen,
533	            Token::Dot,
534	            // ancestor(X, Y) :- parent(X, Z), ancestor(Z, Y).
535	            a("ancestor"), Token::LParen, v("X"), Token::Comma, v("Y"), Token::RParen,
536	            Token::Neck,
537	            a("parent"), Token::LParen, v("X"), Token::Comma, v("Z"), Token::RParen,
538	            Token::Comma,
539	            a("ancestor"), Token::LParen, v("Z"), Token::Comma, v("Y"), Token::RParen,
540	            Token::Dot,
541	            // ?- ancestor(bob, liz).
542	            Token::Query,
543	            a("ancestor"), Token::LParen, a("bob"), Token::Comma, a("liz"),
544	            Token::RParen, Token::Dot,
545	        ]);
546	        let mut atoms = AtomTable::new();
547	        let clauses = parse(&toks, &mut atoms).expect("parse ok");
548	        assert_eq!(clauses.len(), 5);
549	        let kinds: Vec<ClauseKind> = clauses.iter().map(|c| c.kind).collect();
550	        assert_eq!(
551	            kinds,
552	            vec![
553	                ClauseKind::Fact, ClauseKind::Fact, ClauseKind::Rule,
554	                ClauseKind::Rule, ClauseKind::Query,
555	            ]
556	        );
557	        let heads: Vec<&str> = clauses
558	            .iter()
559	            .map(|c| match c.head {
560	                Term::Struct { functor, .. } => name_of(&atoms, functor),
561	                Term::Nil => "",
562	                _ => "?",
563	            })
564	            .collect();
565	        assert_eq!(heads, vec!["parent", "parent", "ancestor", "ancestor", ""]);
566	        // Body of rule 2 has two goals.
567	        assert_eq!(clauses.get(3).unwrap().body.len(), 2);
568	    }
569	
570	    #[test]
571	    fn list_sugar_three_elements() {
572	        // foo([a, b, c]).
