574	            a("foo"), Token::LParen,
575	            Token::LBracket,
576	            a("a"), Token::Comma, a("b"), Token::Comma, a("c"),
577	            Token::RBracket,
578	            Token::RParen, Token::Dot,
579	        ]);
580	        let mut atoms = AtomTable::new();
581	        let clauses = parse(&toks, &mut atoms).expect("parse ok");
582	        let c = clauses.get(0).unwrap();
583	        // head = foo(X) where X is a list struct
584	        let (functor, args) = match c.head {
585	            Term::Struct { functor, args } => (functor, args),
586	            _ => panic!("head not struct"),
587	        };
588	        assert_eq!(name_of(&atoms, functor), "foo");
589	        assert_eq!(args.len(), 1);
590	        // Walk the cons list: '.'(a, '.'(b, '.'(c, []))).
591	        let mut cur_idx = *args.get(0).unwrap();
592	        let expected = ["a", "b", "c"];
593	        for want in expected {
594	            let node = c.subterm(cur_idx).copied().expect("cons node present");
595	            let (f, a2) = match node {
596	                Term::Struct { functor, args } => (functor, args),
597	                _ => panic!("expected cons, got {:?}", node),
598	            };
599	            assert_eq!(name_of(&atoms, f), ".");
600	            assert_eq!(a2.len(), 2);
601	            let head_idx = *a2.get(0).unwrap();
602	            let tail_idx = *a2.get(1).unwrap();
603	            let head = c.subterm(head_idx).copied().unwrap();
604	            match head {
605	                Term::Atom(aid) => assert_eq!(name_of(&atoms, aid), want),
606	                _ => panic!("list head not atom"),
607	            }
608	            cur_idx = tail_idx;
609	        }
610	        // Final tail should be Nil.
611	        let end = c.subterm(cur_idx).copied().unwrap();
612	        assert!(matches!(end, Term::Nil));
613	    }
