1	//! `BoundedArr<T, N>`: stack-allocated fixed-capacity array.
2	//!
3	//! Mirrors a SNOBOL4 ARRAY with explicit length discipline. `push`
4	//! fails with `PortError::Overflow` at capacity — no reallocation.
5	
6	use super::error::PortError;
7	
8	#[derive(Clone, Copy, Debug, PartialEq, Eq)]
9	pub struct BoundedArr<T: Copy, const N: usize> {
10	    data: [Option<T>; N],
11	    len: usize,
12	}
13	
14	impl<T: Copy, const N: usize> BoundedArr<T, N> {
15	    pub const fn new() -> Self {
16	        Self { data: [None; N], len: 0 }
17	    }
